import{c as t,Q as a,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"From Rows to Reasoning: A Retrieval-Augmented Multimodal Framework for Spreadsheet Understanding","description":"","frontmatter":{"title":"From Rows to Reasoning: A Retrieval-Augmented Multimodal Framework for Spreadsheet Understanding","arxiv_id":2601.08741,"authors":"Anmol Gulati, Sahil Sen, Waqar Sarguroh, Kevin Paul","fetched":"2026-05-26T00:00:00.000Z","published":"2026-01-13T00:00:00.000Z","source":"https://arxiv.org/abs/2601.08741","source_tier":"P"},"headers":[],"relativePath":"research/papers/2026-01-13-from-rows-to-reasoning-2601-08741.md","filePath":"research/papers/2026-01-13-from-rows-to-reasoning-2601-08741.md","lastUpdated":1779935873000}'),i={name:"research/papers/2026-01-13-from-rows-to-reasoning-2601-08741.md"};function s(o,e,d,l,c,h){return a(),r("div",null,[...e[0]||(e[0]=[n(`<h1 id="from-rows-to-reasoning-a-retrieval-augmented-multimodal-framework-for-spreadsheet-understanding" tabindex="-1">From Rows to Reasoning: A Retrieval-Augmented Multimodal Framework for Spreadsheet Understanding <a class="header-anchor" href="#from-rows-to-reasoning-a-retrieval-augmented-multimodal-framework-for-spreadsheet-understanding" aria-label="Permalink to &quot;From Rows to Reasoning: A Retrieval-Augmented Multimodal Framework for Spreadsheet Understanding&quot;">​</a></h1><p><strong>Authors</strong>: Anmol Gulati, Sahil Sen, Waqar Sarguroh, Kevin Paul (Commercial Technology and Innovation Office, PricewaterhouseCoopers U.S.) <strong>Published</strong>: January 2026 (v1: 2026-01-13; v2: 2026-02-09) <strong>Source</strong>: <a href="https://arxiv.org/abs/2601.08741" target="_blank" rel="noreferrer">https://arxiv.org/abs/2601.08741</a><strong>arXiv ID</strong>: 2601.08741 <strong>Categories</strong>: cs.CL (Computation and Language)</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>Large Language Models (LLMs) struggle to reason over large-scale enterprise spreadsheets containing thousands of numeric rows, multiple linked sheets, and embedded visual content such as charts and receipts. Prior state-of-the-art spreadsheet reasoning approaches typically rely on single-sheet compression or full-context encoding, which limits scalability and fails to reflect how real users interact with complex, multimodal workbooks. We introduce FRTR-Bench, the first large-scale benchmark for multimodal spreadsheet reasoning, comprising 30 enterprise-grade Excel workbooks spanning nearly four million cells and more than 50 embedded images. To address these challenges, we present From Rows to Reasoning (FRTR), an advanced, multimodal retrieval-augmented generation framework that decomposes Excel workbooks into granular row, column, and block embeddings, employs hybrid lexical-dense retrieval with Reciprocal Rank Fusion (RRF), and integrates multimodal embeddings to reason over both numerical and visual information. We tested FRTR on six LLMs, achieving 74% answer accuracy on FRTR-Bench with Claude Sonnet 4.5, a substantial improvement over prior state-of-the-art approaches that reached only 24%. On the SpreadsheetLLM benchmark, FRTR achieved 87% accuracy with GPT-5 while reducing token usage by roughly 50% compared to direct serialization methods.</p><p><strong>Keywords</strong>: Large Language Models, Retrieval-Augmented Generation (RAG), Multimodal Data Retrieval, Scalable Numerical Reasoning</p><hr><h2 id="core-thesis" tabindex="-1">Core Thesis <a class="header-anchor" href="#core-thesis" aria-label="Permalink to &quot;Core Thesis&quot;">​</a></h2><p>FRTR reframes enterprise spreadsheet analysis as a three-stage pipeline (Retrieve → Verify → Compose) using hybrid lexical-dense retrieval with RRF to surface only the minimal relevant evidence, bypassing LLM context limits entirely. By decomposing workbooks into multi-granular units (rows, columns, sliding windows, embedded images) and indexing them in a shared multimodal vector space, FRTR achieves 2–4× higher accuracy than compression-based approaches at 40% lower token cost, while preserving full provenance for audit compliance.</p><hr><h2 id="_1-introduction" tabindex="-1">1. Introduction <a class="header-anchor" href="#_1-introduction" aria-label="Permalink to &quot;1. Introduction&quot;">​</a></h2><p>Spreadsheets remain the foundational medium for analytical work at an enterprise level, and modern workbooks routinely contain thousands of cells, span multiple sheets, and embed diverse media such as charts, receipts, and scanned tables. While LLMs promise intuitive natural-language interaction with such documents, directly serializing entire sheets into a prompt is inefficient and brittle. Spreadsheet semantics hinge on spatial layout, structural dependencies, and cross-sheet relationships rather than text alone. Moreover, recent work shows that long-context LLMs suffer positional degradation — accuracy declines when relevant information appears far from the prompt boundaries.</p><p>This motivates retrieval-focused approaches that surface small, relevant subsets rather than streaming full spreadsheets into the context window.</p><p>A prominent prior direction is SpreadsheetLLM, which introduces encoding schemes (SheetEncoder and SheetCompressor) that compress cell content, positional addresses, and formatting to fit within an LLM&#39;s context window. While effective for single-sheet reasoning, such compression assumes all relevant data can fit within a single prompt and fails to scale to multi-sheet or multimodal settings.</p><p><strong>Three novel contributions of this work:</strong></p><ol><li><strong>Retrieval-first framework</strong>: An advanced, multimodal RAG approach integrating hybrid lexical-dense retrieval to overcome full-context limitations and improve scalability.</li><li><strong>Multi-granular and multimodal indexing</strong>: Fine-grained indexing at row, column, and block levels, extended to multimodal settings using joint text-vision embeddings. Hybrid rank-fusion retrieval ensures robust performance across both textual and image-bearing spreadsheets.</li><li><strong>FRTR-Bench benchmark</strong>: The first large-scale, multimodal spreadsheet reasoning benchmark spanning 30 enterprise-grade workbooks with nearly four million cells and over fifty embedded images.</li></ol><p>Token scaling comparison: naive full-context serialization exceeds context limits as data grows, while FRTR maintains constant token usage (~8K) via selective retrieval.</p><hr><h2 id="_2-related-work" tabindex="-1">2. Related Work <a class="header-anchor" href="#_2-related-work" aria-label="Permalink to &quot;2. Related Work&quot;">​</a></h2><h3 id="_2-1-llms-for-tables-and-spreadsheets" tabindex="-1">2.1. LLMs for Tables and Spreadsheets <a class="header-anchor" href="#_2-1-llms-for-tables-and-spreadsheets" aria-label="Permalink to &quot;2.1. LLMs for Tables and Spreadsheets&quot;">​</a></h3><p>Early neural models such as TAPAS learned to answer questions directly over tables by encoding cell values jointly with queries, while TUTA extended this paradigm by modeling hierarchical and spatial cues. OmniTab improved few-shot table QA by combining natural and synthetic supervision. These approaches focus on in-context reasoning within a single table and do not scale to multi-sheet or multimodal workbooks.</p><p>More recent work such as SpreadsheetLLM compresses spreadsheet structure and content to fit within LLM context limits, achieving notable gains on single-sheet reasoning. Complementary methods including Table-GPT and TableLLM improve general table manipulation and code generation capabilities. However, these approaches are not capable of handling cross-sheet and multimodal reasoning.</p><h3 id="_2-2-long-context-retrieval-and-hybrid-search" tabindex="-1">2.2. Long Context, Retrieval, and Hybrid Search <a class="header-anchor" href="#_2-2-long-context-retrieval-and-hybrid-search" aria-label="Permalink to &quot;2.2. Long Context, Retrieval, and Hybrid Search&quot;">​</a></h3><p>Despite advances in long-context modeling, evidence retrieval remains a bottleneck: simply extending context windows does not guarantee that models attend effectively to mid-range information. RAG approaches address this by selecting relevant evidence before generation, improving both performance and interpretability. Hybrid lexical-dense retrieval, fused through methods such as RRF, offers robustness and simplicity across tasks. However, basic chunking and retrieval methodologies do not take into account the complicated spatial relationships in spreadsheets, where logic can apply across rows, columns, and even sheets.</p><h3 id="_2-3-multimodal-spreadsheet-understanding-and-document-vqa" tabindex="-1">2.3. Multimodal Spreadsheet Understanding and Document VQA <a class="header-anchor" href="#_2-3-multimodal-spreadsheet-understanding-and-document-vqa" aria-label="Permalink to &quot;2.3. Multimodal Spreadsheet Understanding and Document VQA&quot;">​</a></h3><p>Spreadsheets often convey semantics through visual layout (bold headers, merged cells, shaded totals) as well as through embedded images such as charts or scanned receipts. Vision-language models still struggle to interpret such spatial and structural cues. Parallel research in chart and document VQA (ChartQA, DocVQA) highlights the challenges of numerically grounded visual reasoning. These methods typically treat visual and textual modalities in isolation, without integrating multimodal embeddings that unify text, layout, and image semantics.</p><h3 id="_2-4-benchmarks-for-spreadsheet-interaction" tabindex="-1">2.4. Benchmarks for Spreadsheet Interaction <a class="header-anchor" href="#_2-4-benchmarks-for-spreadsheet-interaction" aria-label="Permalink to &quot;2.4. Benchmarks for Spreadsheet Interaction&quot;">​</a></h3><p>Beyond table QA, recent benchmarks target spreadsheet interaction directly. SpreadsheetLLM performs reasoning on encoded spreadsheets, while SpreadsheetBench introduces realistic, forum-based spreadsheet questions. InstructExcel focuses on natural-language-to-OfficeScript translation. No existing benchmarks assess cross-sheet reasoning, multimodal queries, and large-scale evaluation together.</p><hr><h2 id="_3-framework-overview" tabindex="-1">3. Framework Overview <a class="header-anchor" href="#_3-framework-overview" aria-label="Permalink to &quot;3. Framework Overview&quot;">​</a></h2><h3 id="_3-1-motivation-and-design-goals" tabindex="-1">3.1. Motivation and Design Goals <a class="header-anchor" href="#_3-1-motivation-and-design-goals" aria-label="Permalink to &quot;3.1. Motivation and Design Goals&quot;">​</a></h3><p>Real-world Excel workbooks exhibit three intertwined challenges: scale, multimodality, and cross-sheet dependency. Workbooks can span thousands of rows across multiple worksheets, include embedded charts or receipts, and encode meaning through layout and formatting. FRTR does not assume well-formed tables; its use of overlapping row-, column-, and window-level units allows relevant evidence to be retrieved even when logical groupings are not strictly aligned with grid boundaries.</p><p><strong>Three guiding principles:</strong></p><ol><li><strong>Scalability</strong>: Decompose workbooks into granular, retrievable units (rows, columns, blocks, images) to bypass context limits, deduplicating merged cells and representing both formulas and calculated values.</li><li><strong>Auditability</strong>: Ensure transparent provenance via hybrid retrieval with RRF, supporting verifiable reasoning.</li><li><strong>Multimodality</strong>: Use joint text-vision embeddings so that both tabular and visual content contribute to retrieval and reasoning.</li></ol><h3 id="_3-2-architecture-overview" tabindex="-1">3.2. Architecture Overview <a class="header-anchor" href="#_3-2-architecture-overview" aria-label="Permalink to &quot;3.2. Architecture Overview&quot;">​</a></h3><p>FRTR operates in three stages: <strong>Retrieve</strong>, <strong>Verify</strong>, and <strong>Compose</strong>.</p><p>During ingestion, Excel workbooks are decomposed into rows, columns, sliding windows, and embedded images. Each unit is serialized and embedded using a multimodal encoder (Amazon Titan Multimodal) and indexed in a hybrid vector database. At query time, FRTR retrieves the most relevant units using hybrid lexical-dense search and provides the fused results as evidence for LLM reasoning. This architecture reduces context size while preserving interpretability and scalability.</p><h3 id="_3-3-retrieval-and-fusion-layer" tabindex="-1">3.3. Retrieval and Fusion Layer <a class="header-anchor" href="#_3-3-retrieval-and-fusion-layer" aria-label="Permalink to &quot;3.3. Retrieval and Fusion Layer&quot;">​</a></h3><p>Each spreadsheet unit is indexed as a structured document with lexical, vector, and metadata fields. FRTR performs two parallel retrievals: BM25 for lexical matching and cosine similarity for dense embeddings, and fuses results via Reciprocal Rank Fusion (RRF):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>RRF(d) = Σ_{r∈R} 1 / (k + rank_r(d))</span></span></code></pre></div><p>where k = 60 stabilizes low-ranked items. FRTR uses K_v = K_s = 20, returning the top-10 fused items annotated with provenance. This rank-based fusion avoids score normalization issues, ensuring robust, interpretable retrieval across modalities. RRF is used because it provides the most robust retrieval across both paraphrased queries and exact identifier lookups common in spreadsheet QA.</p><p><strong>Algorithm 1 — FRTR: From Rows to Reasoning</strong></p><ul><li><strong>Stage 1 (Indexing, Offline)</strong>: For each sheet, compute adaptive window size s = ⌈√(N/K_target)⌉. For each unit u ∈ {rows, columns, s×s windows, images}: compute multimodal embedding v_u = E(u) and add (text(u), v_u, metadata(u)) to index D.</li><li><strong>Stage 2 (Hybrid Retrieval, Online)</strong>: Embed query q; retrieve top-K_v by cosine similarity (dense) and top-K_s by BM25 (lexical); compute RRF scores; return top-K chunks C with provenance labels.</li><li><strong>Stage 3 (Answer Composition)</strong>: Construct prompt P = {q, C, instruction}; invoke LLM M; parse JSON response {reasoning, answer}.</li></ul><h3 id="_3-4-multimodal-embedding-layer" tabindex="-1">3.4. Multimodal Embedding Layer <a class="header-anchor" href="#_3-4-multimodal-embedding-layer" aria-label="Permalink to &quot;3.4. Multimodal Embedding Layer&quot;">​</a></h3><p>For text-based units, FRTR serializes contextual information preserving spatial cues:</p><ul><li><strong>Rows</strong>: include column headers</li><li><strong>Columns</strong>: include row indices</li><li><strong>Windows</strong>: preserve s×s spatial layout</li></ul><p>Image units (charts, receipts, diagrams) are embedded using the vision branch of the same model, ensuring a shared latent space. Images are encoded as base64 and passed to the Titan Image-v1 embeddings API. This allows queries such as &quot;Q4 revenue trends&quot; to retrieve both numerical data and corresponding charts. A unified vector field holds both text and image representations, enabling cross-modal retrieval within a single index.</p><h3 id="_3-5-reasoning-and-output-generation" tabindex="-1">3.5. Reasoning and Output Generation <a class="header-anchor" href="#_3-5-reasoning-and-output-generation" aria-label="Permalink to &quot;3.5. Reasoning and Output Generation&quot;">​</a></h3><p>After retrieval, FRTR invokes an LLM with a structured prompt containing the query, retrieved chunks, and reasoning instructions. Each chunk is formatted with explicit metadata:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Chunk 1 (Score: 0.0164, Source: Vector)</span></span>
<span class="line"><span>Type: row | Sheet: Sales_Q4</span></span>
<span class="line"><span>ROW_42: Product | Units | Revenue | ...</span></span></code></pre></div><p>The LLM produces structured JSON outputs:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;reasoning&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Analyzed columns B and C for revenue values.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;answer&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;SUM(B2:B15)&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>This format ensures both interpretability and machine-readability, facilitating downstream automation and audit compliance. FRTR itself does not execute formulas or modify spreadsheets, maintaining human oversight while ensuring verifiable, grounded reasoning.</p><hr><h2 id="_4-frtr-bench-benchmark-for-spreadsheet-reasoning" tabindex="-1">4. FRTR-Bench: Benchmark for Spreadsheet Reasoning <a class="header-anchor" href="#_4-frtr-bench-benchmark-for-spreadsheet-reasoning" aria-label="Permalink to &quot;4. FRTR-Bench: Benchmark for Spreadsheet Reasoning&quot;">​</a></h2><h3 id="_4-1-dataset-construction" tabindex="-1">4.1. Dataset Construction <a class="header-anchor" href="#_4-1-dataset-construction" aria-label="Permalink to &quot;4.1. Dataset Construction&quot;">​</a></h3><p>To evaluate cross-sheet and multimodal reasoning at scale, FRTR-Bench comprises 30 multimodal Excel workbooks across diverse domains. Each workbook stresses three dimensions:</p><ol><li><strong>Scale</strong>: up to 210,000 rows per workbook, far beyond typical LLM context</li><li><strong>Multimodality</strong>: embedded PNG images (charts, receipts, dashboards)</li><li><strong>Cross-sheet complexity</strong>: multi-sheet references (e.g., <code>=SUM(Sheet1!B2:B100, Sheet2!C5:C50)</code>)</li></ol><p><strong>Difficulty tiers by scale:</strong></p><ul><li><strong>Easy</strong>: &lt; 5,000 rows — small business summaries</li><li><strong>Medium</strong>: 5,000–20,000 rows — mid-size audit or operations data</li><li><strong>Hard</strong>: 20,000–210,000 rows — large-scale consolidation workbooks</li></ul><p>Domains include finance, supply chain, healthcare, energy, government, education, and others. Each workbook includes a metadata sheet, 1–5 data sheets, embedded PNGs with captions, and a Questions sheet containing 5–10 manually crafted queries with explicit provenance (e.g., <code>Sheet1!B5</code> or <code>Image ID: Chart_001</code>).</p><h3 id="_4-2-evaluation-protocol" tabindex="-1">4.2. Evaluation Protocol <a class="header-anchor" href="#_4-2-evaluation-protocol" aria-label="Permalink to &quot;4.2. Evaluation Protocol&quot;">​</a></h3><p><strong>Answer Accuracy</strong>: Comparing model outputs with annotated ground-truth answers and provenance (cells, formulas, or images). Answers are correct if numerically consistent or functionally identical in formula logic (e.g., <code>SUM(B2:B10)</code> vs. <code>SUM(B2:B5)+SUM(B6:B10)</code>).</p><p><strong>Latency</strong>: Average response time per query (not including embedding and retrieval), measured from user query submission to model output generation.</p><p><strong>Mean Tokens</strong>: Mean number of tokens per model input after retrieval and formatting. Lower token counts indicate more efficient retrieval.</p><h3 id="_4-3-benchmark-statistics" tabindex="-1">4.3. Benchmark Statistics <a class="header-anchor" href="#_4-3-benchmark-statistics" aria-label="Permalink to &quot;4.3. Benchmark Statistics&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Metric</th><th>Count</th></tr></thead><tbody><tr><td>Workbooks</td><td>30</td></tr><tr><td>Sheets</td><td>155</td></tr><tr><td>Rows</td><td>656,457</td></tr><tr><td>Cells</td><td>3,928,934</td></tr><tr><td>Embedded Images</td><td>53</td></tr><tr><td>Cross-Sheet Formulas</td><td>30</td></tr><tr><td>Questions</td><td>157</td></tr></tbody></table><p><strong>Example question</strong> (from <code>frtr_0003_consolidation.xlsx</code>, Hard, 49,867 rows):</p><ul><li>Question: &quot;What is the consolidated operating income for Region EMEA in FY2024?&quot;</li><li>ReasoningType: cross-sheet</li><li>Provenance: <code>Consolidation!E47</code>, <code>=SUM(EMEA_Sales!D:D,EMEA_Ops!E:E)</code></li><li>Answer: $12,450,000</li></ul><hr><h2 id="_5-evaluation" tabindex="-1">5. Evaluation <a class="header-anchor" href="#_5-evaluation" aria-label="Permalink to &quot;5. Evaluation&quot;">​</a></h2><h3 id="_5-1-experiment-1-—-frtr-bench-evaluation" tabindex="-1">5.1. Experiment 1 — FRTR-Bench Evaluation <a class="header-anchor" href="#_5-1-experiment-1-—-frtr-bench-evaluation" aria-label="Permalink to &quot;5.1. Experiment 1 — FRTR-Bench Evaluation&quot;">​</a></h3><h4 id="results-table-2-performance-comparison-on-frtr-bench" tabindex="-1">Results (Table 2): Performance comparison on FRTR-Bench <a class="header-anchor" href="#results-table-2-performance-comparison-on-frtr-bench" aria-label="Permalink to &quot;Results (Table 2): Performance comparison on FRTR-Bench&quot;">​</a></h4><p>Mean tokens: FRTR 7,691; SpreadsheetLLM 12,745 (FRTR uses ~40% fewer tokens).</p><table tabindex="0"><thead><tr><th>Model</th><th>FRTR Accuracy</th><th>FRTR Latency (s)</th><th>SpreadsheetLLM Accuracy</th><th>SpreadsheetLLM Latency (s)</th><th>ΔAccuracy</th></tr></thead><tbody><tr><td>GPT-4o</td><td>0.49</td><td>5.04</td><td>0.06</td><td>1.14</td><td>+0.43</td></tr><tr><td>GPT-5</td><td>0.73</td><td>15.50</td><td>0.18</td><td>18.10</td><td>+0.55</td></tr><tr><td>Claude Sonnet 4.5</td><td>0.74</td><td>11.71</td><td>0.13</td><td>8.80</td><td>+0.61</td></tr><tr><td>Gemini 2.5 Pro</td><td>0.67</td><td>26.90</td><td>0.24</td><td>33.35</td><td>+0.43</td></tr><tr><td>LLaMA Maverick-17B</td><td>0.56</td><td>2.42</td><td>0.23</td><td>1.15</td><td>+0.33</td></tr><tr><td>GPT-OSS-120B</td><td>0.51</td><td>5.75</td><td>0.21</td><td>8.80</td><td>+0.30</td></tr></tbody></table><h4 id="discussion" tabindex="-1">Discussion <a class="header-anchor" href="#discussion" aria-label="Permalink to &quot;Discussion&quot;">​</a></h4><ul><li>FRTR consistently achieves 2–4× higher accuracy, 40% lower token usage, and comparable or lower latency than SpreadsheetLLM.</li><li>On easy workbooks, FRTR attains mean accuracies of 0.86–0.93 for top-tier models vs. SpreadsheetLLM&#39;s 0.18–0.23.</li><li>Performance remains robust on medium (0.62–0.65) and hard (0.66–0.72) tiers, where SpreadsheetLLM collapses below 0.10.</li><li>Average prompt length is only 7.7K tokens vs. SpreadsheetLLM&#39;s 13.1K tokens (251× compression ratio relative to raw workbook size).</li><li>FRTR achieves <strong>65% accuracy</strong> on the 23 image-dependent questions — a capability text-only approaches cannot address at all.</li><li>The U-shaped accuracy pattern (medium difficulty is hardest) reflects structural complexity, not size: very large spreadsheets tend to be transaction logs with repetitive structure, while medium ones represent complex business consolidations with retrieval ambiguity.</li></ul><h3 id="_5-2-experiment-2-—-spreadsheetllm-benchmark-evaluation" tabindex="-1">5.2. Experiment 2 — SpreadsheetLLM Benchmark Evaluation <a class="header-anchor" href="#_5-2-experiment-2-—-spreadsheetllm-benchmark-evaluation" aria-label="Permalink to &quot;5.2. Experiment 2 — SpreadsheetLLM Benchmark Evaluation&quot;">​</a></h3><h4 id="results-table-3-performance-comparison-on-spreadsheetllm-benchmark" tabindex="-1">Results (Table 3): Performance comparison on SpreadsheetLLM benchmark <a class="header-anchor" href="#results-table-3-performance-comparison-on-spreadsheetllm-benchmark" aria-label="Permalink to &quot;Results (Table 3): Performance comparison on SpreadsheetLLM benchmark&quot;">​</a></h4><p>Mean tokens: FRTR 6,920; SpreadsheetLLM 5,811; Naïve full-context 13,631.</p><table tabindex="0"><thead><tr><th>Technique</th><th>Model</th><th>Answer Accuracy</th><th>Latency (s)</th></tr></thead><tbody><tr><td>FRTR</td><td>GPT-4o</td><td>0.77</td><td>2.48</td></tr><tr><td>FRTR</td><td>GPT-5</td><td>0.87</td><td>18.06</td></tr><tr><td>FRTR</td><td>Claude Sonnet 4.5</td><td>0.84</td><td>10.40</td></tr><tr><td>FRTR</td><td>Gemini 2.5 Pro</td><td>0.85</td><td>24.06</td></tr><tr><td>FRTR</td><td>LLaMA Maverick-17B</td><td>0.53</td><td>2.18</td></tr><tr><td>FRTR</td><td>GPT-OSS-120b</td><td>0.75</td><td>7.37</td></tr><tr><td>SpreadsheetLLM</td><td>GPT-4o</td><td>0.78</td><td>0.81</td></tr><tr><td>SpreadsheetLLM</td><td>GPT-5</td><td>0.90</td><td>5.50</td></tr><tr><td>SpreadsheetLLM</td><td>Claude Sonnet 4.5</td><td>0.91</td><td>5.49</td></tr><tr><td>SpreadsheetLLM</td><td>Gemini 2.5 Pro</td><td>0.89</td><td>10.00</td></tr><tr><td>SpreadsheetLLM</td><td>LLaMA Maverick-17B</td><td>0.73</td><td>0.73</td></tr><tr><td>SpreadsheetLLM</td><td>GPT-OSS-120b</td><td>0.80</td><td>4.01</td></tr><tr><td>Naïve Full-Context</td><td>GPT-4o</td><td>0.35</td><td>3.01</td></tr><tr><td>Naïve Full-Context</td><td>GPT-5</td><td>0.68</td><td>18.07</td></tr><tr><td>Naïve Full-Context</td><td>Claude Sonnet 4.5</td><td>0.55</td><td>9.06</td></tr><tr><td>Naïve Full-Context</td><td>Gemini 2.5 Pro</td><td>0.67</td><td>15.48</td></tr><tr><td>Naïve Full-Context</td><td>LLaMA Maverick-17B</td><td>0.41</td><td>2.45</td></tr><tr><td>Naïve Full-Context</td><td>GPT-OSS-120b</td><td>0.59</td><td>8.61</td></tr></tbody></table><h4 id="discussion-1" tabindex="-1">Discussion <a class="header-anchor" href="#discussion-1" aria-label="Permalink to &quot;Discussion&quot;">​</a></h4><p>FRTR performs on par with SpreadsheetLLM in overall accuracy across most model families (0.84–0.87 vs. 0.89–0.91 for high-capacity models) while substantially outperforming the naïve full-context baseline. FRTR considers every sheet in an Excel workbook, while SpreadsheetLLM was given the oracle sheet. FRTR achieves this parity while using roughly 40–50% fewer tokens than the full-context baseline and maintaining stable latency across models. The retrieval-based design also provides explicit provenance for every reasoning step, enabling interpretability that compression-based systems lack.</p><h3 id="_5-3-ablation-studies" tabindex="-1">5.3. Ablation Studies <a class="header-anchor" href="#_5-3-ablation-studies" aria-label="Permalink to &quot;5.3. Ablation Studies&quot;">​</a></h3><h4 id="_5-3-1-retrieval-method-ablation-table-4" tabindex="-1">5.3.1. Retrieval Method Ablation (Table 4) <a class="header-anchor" href="#_5-3-1-retrieval-method-ablation-table-4" aria-label="Permalink to &quot;5.3.1. Retrieval Method Ablation (Table 4)&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Retrieval Method</th><th>Answer Accuracy</th><th>Avg Retrieval Time (s)</th><th>Avg Tokens</th></tr></thead><tbody><tr><td>Hybrid (RRF)</td><td><strong>0.74</strong></td><td>0.82</td><td>6,903</td></tr><tr><td>Vector Only</td><td>0.59</td><td>0.70</td><td>5,857</td></tr><tr><td>BM25/Lexical Only</td><td>0.42</td><td><strong>0.11</strong></td><td>5,616</td></tr></tbody></table><p>Hybrid RRF achieves significantly higher accuracy by combining exact-match patterns (BM25) with semantic similarity (dense), validating the design choice for RRF-based hybrid retrieval.</p><h4 id="_5-3-2-unit-granularity-ablation-table-5" tabindex="-1">5.3.2. Unit Granularity Ablation (Table 5) <a class="header-anchor" href="#_5-3-2-unit-granularity-ablation-table-5" aria-label="Permalink to &quot;5.3.2. Unit Granularity Ablation (Table 5)&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Units Retrieved</th><th>Answer Accuracy</th><th>Avg LLM Time (s)</th><th>Avg Tokens</th></tr></thead><tbody><tr><td>Rows</td><td>0.52</td><td>7.55</td><td>2,017</td></tr><tr><td>Columns</td><td>0.18</td><td>5.34</td><td>11,465</td></tr><tr><td>Windows</td><td>0.58</td><td>7.15</td><td>7,259</td></tr><tr><td>All Types (FRTR)</td><td><strong>0.74</strong></td><td>11.71</td><td>7,690</td></tr></tbody></table><p>Different granularities capture complementary information. Combining all unit types (rows + columns + windows + images) achieves the highest accuracy, demonstrating that multi-granular indexing surfaces relevant evidence regardless of query structure. FRTR&#39;s multi-granular approach outperforms SpreadsheetLLM (0.24 accuracy) by over 3×.</p><h3 id="_5-4-cost-analysis" tabindex="-1">5.4. Cost Analysis <a class="header-anchor" href="#_5-4-cost-analysis" aria-label="Permalink to &quot;5.4. Cost Analysis&quot;">​</a></h3><p>FRTR uses 7,691 tokens on average vs. SpreadsheetLLM&#39;s 12,745 tokens (40% reduction). At typical API rates ($0.01–0.03 per 1K input tokens for frontier models), for an enterprise processing 1,000 queries daily, FRTR would reduce annual LLM costs by approximately 40% while improving accuracy. Embedding costs are incurred once during indexing and amortized across all subsequent queries.</p><hr><h2 id="_6-limitations" tabindex="-1">6. Limitations <a class="header-anchor" href="#_6-limitations" aria-label="Permalink to &quot;6. Limitations&quot;">​</a></h2><ol><li>Multimodal image accuracy (65%) is promising but has room for improvement as enterprise-grade multimodal encoders mature.</li><li>FRTR-Bench focuses on English-language spreadsheets, though the retrieval architecture is language-agnostic.</li><li>FRTR generates formulas and cell references rather than executing them, preserving human oversight aligned with enterprise audit requirements.</li><li>Initial workbook indexing is a one-time cost (alleviated by batch processing and parallelization); retrieval latency is negligible once indexed (under 1 second).</li></ol><hr><h2 id="_7-ethics-and-reproducibility" tabindex="-1">7. Ethics and Reproducibility <a class="header-anchor" href="#_7-ethics-and-reproducibility" aria-label="Permalink to &quot;7. Ethics and Reproducibility&quot;">​</a></h2><p>FRTR-Bench consists of synthetic enterprise-style workbooks designed to simulate realistic analytical scenarios without using real user data or proprietary information. The benchmark is available at: <a href="https://github.com/AnmolGulati6/FRTR-bench" target="_blank" rel="noreferrer">https://github.com/AnmolGulati6/FRTR-bench</a></p><hr><h2 id="_8-conclusion" tabindex="-1">8. Conclusion <a class="header-anchor" href="#_8-conclusion" aria-label="Permalink to &quot;8. Conclusion&quot;">​</a></h2><p>FRTR introduces a retrieval-first multimodal RAG framework that decomposes spreadsheets into granular row, column, and block embeddings, employs hybrid lexical-dense retrieval with RRF, and integrates multimodal embeddings to reason jointly over numerical and visual content. Key results:</p><ul><li><strong>74% accuracy</strong> on FRTR-Bench (vs. 24% prior state-of-the-art) — 50 percentage points improvement</li><li><strong>87% accuracy</strong> on SpreadsheetLLM benchmark with GPT-5</li><li><strong>~50% token reduction</strong> vs. full-context baseline</li><li><strong>65% accuracy</strong> on image-dependent questions (vs. 0% for text-only approaches)</li><li><strong>40% cost reduction</strong> at enterprise query volumes</li></ul><p>Future work: adaptive retrieval, finer multimodal alignment, and agentic spreadsheet manipulation.</p><hr><h2 id="key-references" tabindex="-1">Key References <a class="header-anchor" href="#key-references" aria-label="Permalink to &quot;Key References&quot;">​</a></h2><ul><li><strong>SpreadsheetLLM</strong> (Dong et al., 2025): SheetEncoder and SheetCompressor for single-sheet reasoning — primary baseline. GitHub: <a href="https://github.com/microsoft/SpreadsheetLLM" target="_blank" rel="noreferrer">https://github.com/microsoft/SpreadsheetLLM</a></li><li><strong>SpreadsheetBench</strong> (Ma et al., 2024): Realistic, forum-based spreadsheet questions benchmark.</li><li><strong>InstructExcel</strong> (Payan et al., 2023): Natural-language-to-OfficeScript translation benchmark.</li><li><strong>TAPAS</strong> (Herzig et al., 2020): Neural table QA by encoding cell values jointly with queries.</li><li><strong>TUTA</strong> (Wang et al., 2021): Table understanding with hierarchical and spatial cues.</li><li><strong>OmniTab</strong> (Jiang et al., 2022): Few-shot table QA combining natural and synthetic supervision.</li><li><strong>Table-GPT</strong> (Zha et al., 2023): General table manipulation capabilities.</li><li><strong>Reciprocal Rank Fusion</strong> (Cormack et al., 2009): Rank fusion method for hybrid retrieval. SIGIR &#39;09, pp. 758–759.</li><li><strong>RAG</strong> (Lewis et al., 2021): Retrieval-augmented generation for NLP.</li><li><strong>Lost in the Middle</strong> (Liu et al., 2023): Positional degradation in long-context LLMs.</li><li><strong>RETRO</strong> (Borgeaud et al., 2022): Improving language models by retrieving from trillions of tokens.</li><li><strong>ChartQA</strong> (Masry et al., 2022): Chart question answering benchmark.</li><li><strong>DocVQA</strong> (Mathew et al., 2021): Document visual question answering benchmark.</li><li><strong>Amazon Titan Multimodal Embeddings G1</strong> (AWS, 2025): Multimodal encoder used in FRTR implementation.</li><li><strong>Abootorabi et al. (2025)</strong>: Survey on multimodal retrieval-augmented generation. arXiv:2502.08826.</li><li><strong>Frank et al. (2025)</strong>: Jackal execution-based benchmark for text-to-JQL tasks.</li></ul>`,106)])])}const p=t(i,[["render",s]]);export{m as __pageData,p as default};
